```python
def find_rectangles(grid):
    H=len(grid); W=len(grid[0])
    rects=[]
    for top in range(H):
        for left in range(W):
            border_color=grid[top][left]
            if border_color==0: continue
            for bottom in range(top+2,H):
                # skip bottom row ??? eventually
                for right in range(left+2,W):
                    if grid[top][right]!=border_color or grid[bottom][left]!=border_color or grid[bottom][right]!=border_color:
                        continue
                    # check border
                    ok=True
                    for c in range(left,right+1):
                        if grid[top][c]!=border_color or grid[bottom][c]!=border_color:
                            ok=False; break
                    if not ok: continue
                    for r in range(top,bottom+1):
                        if grid[r][left]!=border_color or grid[r][right]!=border_color:
                            ok=False; break
                    if not ok: continue
                    # interior uniform nonzero different
                    interior_color=None
                    for r in range(top+1,bottom):
                        for c in range(left+1,right):
                            col=grid[r][c]
                            if col==border_color or col==0:
                                ok=False; break
                            if interior_color is None:
                                interior_color=col
                            elif col!=interior_color:
                                ok=False; break
                        if not ok: break
                    if not ok or interior_color is None:
                        continue
                    rects.append(((top,left,bottom,right),border_color,interior_color))
    return rects

rects_test=find_rectangles(test_grid)
rects_test
